版本本案例使用的 Angular 7.x 版本，Material 7.x 版本，但不限于此版本。
新建Angular指令新建指令命令：ng generate directive dialog-draggable


指令中拖拽功能代码实现：
import &#123; Directive, HostListener, OnInit &#125; from &#x27;@angular/core&#x27;;import &#123; MatDialogContainer, MatDialogRef &#125; from &#x27;@angular/material&#x27;;import &#123; Subscription, fromEvent &#125; from &#x27;rxjs&#x27;;import &#123; takeUntil &#125; from &#x27;rxjs/operators&#x27;;export interface Position &#123;  x: number;  y: number;&#125;@Directive(&#123;  selector: &#x27;[dialog-draggable]&#x27;&#125;)export class DialogDraggableDirective implements OnInit &#123;  private _subscription: Subscription;  mouseStart: Position;  mouseDelta: Position;  offset: Position;  constructor(    private matDialogRef: MatDialogRef&lt;any&gt;,    private container: MatDialogContainer  ) &#123;  &#125;  ngOnInit() &#123;    this.offset = this._getOffset();    this._updatePosition(this.offset.y, this.offset.x);  &#125;  @HostListener(&#x27;mousedown&#x27;, [&#x27;$event&#x27;])  onMouseDown(event: MouseEvent) &#123;    this.mouseStart = &#123; x: event.pageX, y: event.pageY &#125;;    const mouseup$ = fromEvent(document, &#x27;mouseup&#x27;);    this._subscription = mouseup$.subscribe(() =&gt; this.onMouseup());    const mousemove$ = fromEvent(document, &#x27;mousemove&#x27;)      .pipe(takeUntil(mouseup$))      .subscribe((e: MouseEvent) =&gt; this.onMouseMove(e));    this._subscription.add(mousemove$);  &#125;  onMouseMove(event: MouseEvent) &#123;    this.mouseDelta = &#123; x: (event.pageX - this.mouseStart.x), y: (event.pageY - this.mouseStart.y) &#125;;    this._updatePosition(this.offset.y + this.mouseDelta.y, this.offset.x + this.mouseDelta.x);  &#125;  onMouseup() &#123;    if (this._subscription) &#123;      this._subscription.unsubscribe();      this._subscription = undefined;    &#125;    if (this.mouseDelta) &#123;      this.offset.x += this.mouseDelta.x;      this.offset.y += this.mouseDelta.y;    &#125;  &#125;  private _updatePosition(top: number, left: number) &#123;    this.matDialogRef.updatePosition(&#123;      top: top + &#x27;px&#x27;,      left: left + &#x27;px&#x27;    &#125;);  &#125;  private _getOffset(): Position &#123;    const box = this.container[&#x27;_elementRef&#x27;].nativeElement.getBoundingClientRect();    return &#123;      x: box.left + pageXOffset,      y: box.top + pageYOffset    &#125;;  &#125;&#125;

在全局的CSS样式文件添加下面的CSS代码：
[dialog-draggable] &#123;  margin: -24px -24px 20px -24px !important;  padding: 10px 24px;  background: #283593 !important;  color: #fff;  cursor: move;&#125;

如何使用在Dialog组件中使用dialog-draggable指令即可实现窗口拖拽，如下
&lt;h2 mat-dialog-title dialog-draggable&gt;  Angular Material Dialog Draggable&lt;/h2&gt;

子绝父相子绝父相：子元素绝对定位，父元素相对定位。
不知道子元素高度和父元素高度的情况.parentElement &#123;    position: relative;&#125;.childElement &#123;    position: absolute;    top: 50%;    transform: translateY(-50%);&#125;

知道子元素高度和父元素高度的情况.parentElement &#123;    position: relative;&#125;.childElement &#123;    position: absolute;    top: 0;    bottom: 0;    left: 0;    right: 0;    margin: auto;&#125;


子元素相对定位父元素设置了高度，而且父元素里面只有一个子元素，可使用子元素相对定位。
.parentElement &#123;    height: xxpx;&#125;.childElement &#123;    position: relative;    top: 50%;    transform: translateY(-50%);&#125;

CSS3 flex如果不考虑低版本浏览器兼容性，用CSS3的flex布局就非常简单咯。
.parentElement &#123;    display: flex;    align-items: center;&#125;

前言可以毫不夸张的说，Node.js的出现带动了整个前端界的繁荣发展，自此进入百花齐放，百家争鸣的时代。时至今天，我们能用Node.js实现很多依靠传统服务器端编程语言才能实现的事，甚至更加简便、更加高效。本案例使用Node.js的net模块，建立服务端与客户端的Socket连接，简单实现了客户端广播消息通信和点对点通信。
项目结构server.js 服务端项目下的server.js是服务端的执行文件，用于创建服务端的Socket服务，监听指定端口；接收客户端传过来的数据，解析数据并按照数据中附带的协议进行广播消息通信或点对点通信。具体代码如下：
// Socket聊天室 - server 服务端const net = require(&#x27;net&#x27;);// 定义clients（键值对集合），用于存储所有的客户端连接，通过用户名去索引客户端socketlet clients = &#123;&#125;;let server = net.createServer((socket) =&gt; &#123;    // 客户端登入    function signin(clientDataContent) &#123;        clientDataContent = JSON.parse(clientDataContent);        let username = clientDataContent.from;        // 如果clients（客户端 socket 集合）中有1个以上的成员，就广播通知所有人谁谁上线了，除了他本身        if (Object.keys(clients).length) &#123;            let onlineNotice = &#123;  // 组成上线通知消息数据格式                protocol: &#x27;online&#x27;,                online: username,                onlineCount: Object.keys(clients).length + 1            &#125;;            // 遍历 clients ，给除了自身的所有客户端发送消息            for (let username in clients) &#123;                if (clients.hasOwnProperty(username)) &#123;                    let noticeClient = clients[username];                    noticeClient.write(JSON.stringify(onlineNotice));                &#125;            &#125;        &#125;        // 将新连接的客户端socket存储于clients        clients[username] = socket;        // 服务端打印上线提示消息        console.log(`欢迎 $&#123;socket.remoteAddress&#125;:$&#123;socket.remotePort&#125;【$&#123;username&#125;】，加入聊天室，当前在线：$&#123;Object.keys(clients).length&#125;`);    &#125;    // 广播消息通信    function broadcast(clientDataContent) &#123;        // 广播出去消息数据格式 json        let sendClientData = JSON.parse(clientDataContent);        // 遍历clients对象（for in），给所有的客户端socket广播消息        for (let username in clients) &#123;            if (clients.hasOwnProperty(username)) &#123;                let client = clients[username];                client.write(JSON.stringify(sendClientData));            &#125;        &#125;    &#125;    // p2p 点对点通信    function p2p(clientDataContent) &#123;        let p2pClientData = JSON.parse(clientDataContent);        // 给指定的客户端发送消息        clients[p2pClientData.to].write(JSON.stringify(p2pClientData));    &#125;    // 给每一个连接服务端的客户端socket注册data事件    socket.on(&#x27;data&#x27;, (chunk) =&gt; &#123;        try &#123;            // 对客户端传过来的数据chunk（json数据）进行序列化            let clientDataContent = chunk.toString().trim();            // 获取协议            let protocol = JSON.parse(clientDataContent).protocol;            switch (protocol) &#123;                case &#x27;signin&#x27;:                    signin(clientDataContent);                    break;                case &#x27;broadcast&#x27;:                    broadcast(clientDataContent);                    break;                case &#x27;p2p&#x27;:                    p2p(clientDataContent);                    break;                default:                    socket.write(&#x27;错误！未能识别的通信协议！&#x27;);                    break;            &#125;        &#125; catch (error) &#123;            socket.write(&#x27;出现错误了哦~&#x27;);            throw error;        &#125;    &#125;);    // 给每一个连接服务端的客户端socket注册error事件，如果连接中断，则触发此事件    socket.on(&#x27;error&#x27;, (error) =&gt; &#123;        // 在客户端对象中，将连接中断的那个客户端删除        let deletekey = null;        // 遍历clients对象，找到下线的socket，并将其删除        for (let username in clients) &#123;            if (clients.hasOwnProperty(username)) &#123;                let client = clients[username];                if (socket === client) deletekey = username;            &#125;        &#125;        delete clients[deletekey];        // 广播通知所有人，谁谁下线了        let offlineNotice = &#123;  // 组成下线通知消息数据格式            protocol: &#x27;offline&#x27;,            offline: deletekey,            onlineCount: Object.keys(clients).length        &#125;;        for (let username in clients) &#123;            if (clients.hasOwnProperty(username)) &#123;                let noticeClient = clients[username];                noticeClient.write(JSON.stringify(offlineNotice));            &#125;        &#125;        // server 消息        console.log(`$&#123;deletekey&#125; 下线了，当前在线：$&#123;Object.keys(clients).length&#125;`);    &#125;);&#125;);// 监听指定端口let port = 2018;server.listen(port, (error) =&gt; &#123;    if (error) &#123;        console.log(`$&#123;port&#125;端口被占用！`);    &#125; else &#123;        console.log(`服务器端正常启动，正在监听$&#123;port&#125;端口`);    &#125;&#125;);


client.js 客户端项目下的client.js是客户端的执行文件，用于创建客户端的Socket服务。将用户输入的内容按特定的格式组成数据结构发给服务端，同时打印出服务端指定的内容。具体代码如下：
// Socket聊天室 - 客户端 clientconst net = require(&#x27;net&#x27;);const readline = require(&#x27;readline&#x27;);const rl = readline.createInterface(process.stdin, process.stdout);rl.question(&#x27;请输入聊天昵称：&#x27;, (nickname) =&gt; &#123;    nickname = nickname.trim();    if (!nickname) &#123;        throw new Error(&#x27;昵称不能为空！&#x27;);    &#125;    // 创建与服务端的连接    // 设置正确的服务端的ip地址和端口    let server = net.connect(&#123;port: 2018, host: &#x27;127.0.0.1&#x27;&#125;, () =&gt; &#123;        // 登入操作        let user = &#123;            protocol: &#x27;signin&#x27;,            from: nickname        &#125;;        // 往服务端传送数据        server.write(JSON.stringify(user));        console.log(`【系统通知】已成功加入聊天室，尽情畅聊吧~`);        // 监听服务端发送过来的数据        server.on(&#x27;data&#x27;, (chunk) =&gt; &#123;            try &#123;                let serverDataContent = JSON.parse(chunk.toString().trim());                let protocol = serverDataContent.protocol;                switch (protocol) &#123;                    case &#x27;online&#x27;:                        console.log(`\n【系统通知】欢迎：$&#123;serverDataContent.online&#125;，加入聊天室，当前在线人数：$&#123;serverDataContent.onlineCount&#125;\n`);                        rl.prompt();                        break;                    case &#x27;offline&#x27;:                        console.log(`\n【系统通知】$&#123;serverDataContent.offline&#125;下线了，当前在线人数：$&#123;serverDataContent.onlineCount&#125;\n`);                        rl.prompt();                        break;                    case &#x27;broadcast&#x27;:                        console.log(`\n[@所有人] $&#123;serverDataContent.from&#125;&gt; $&#123;serverDataContent.message&#125;\n`);                        rl.prompt();                        break;                    case &#x27;p2p&#x27;:                        console.log(`\n[@$&#123;serverDataContent.to&#125;] $&#123;serverDataContent.from&#125;&gt; $&#123;serverDataContent.message&#125;\n`);                        rl.prompt();                        break;                    default:                        server.write(&#x27;错误！未能识别的通信协议！&#x27;);                        break;                &#125;            &#125; catch (error) &#123;                server.write(&#x27;出现错误了哦~&#x27;);                throw error;            &#125;        &#125;);        rl.setPrompt(nickname + &#x27;&gt; &#x27;);  // 此时没有写入控制台        rl.prompt(); // 写入控制台        // 输入一行内容敲回车        rl.on(&#x27;line&#x27;, (line) =&gt; &#123;            line = line.toString().trim();            // 内容： user1:我只跟你说话  表示，客户端用户只跟user1通信            // 根据客户端用户输入的内容按“:”分割成两部分            let arrString = line.split(&#x27;:&#x27;);            let sendServerData = null;            // 组成往服务端发送的数据格式            if (arrString.length === 2) &#123;                // 点对点                sendServerData = &#123;                    protocol: &#x27;p2p&#x27;,                    from: nickname,                    to: arrString[0],                    message: arrString[1]                &#125;;            &#125; else &#123;                // 广播消息                sendServerData = &#123;                    protocol: &#x27;broadcast&#x27;,                    from: nickname,                    message: line                &#125;;            &#125;            // 往服务端发送数据            server.write(JSON.stringify(sendServerData));            rl.prompt(); // 写入控制台        &#125;);        rl.on(&#x27;close&#x27;, () =&gt; &#123;        &#125;);    &#125;);&#125;);

实现功能目前已实现：客户端广播消息通信、点对点通信。
项目使用
启动服务端，$ node server.js
启动第一个客户端，$ node client.js
启动第二个客户端，$ node client.js
……

